import React, { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import UserProfile from "../../components/UserProfile/UserProfile";
import ProgressModal from "../../components/ProgressModal/ProgressModal";
import { workoutsService } from "../../services/workouts.service";
import { coursesService } from "../../services/courses.service";
import styles from "./TrainingPageWithModal.module.css";

interface Exercise {
  _id: string;
  name: string;
  quantity: number;
}

interface TrainingPageWithModalProps {
  userName?: string;
  userEmail?: string;
  token?: string;
  onLogout?: () => void;
}

const TrainingPageWithModal: React.FC<TrainingPageWithModalProps> = ({
  userName = "",
  userEmail = "",
  token,
  onLogout,
}) => {
  const navigate = useNavigate();
  const { id } = useParams<{ id: string }>();
  const [exercises, setExercises] = useState<Exercise[]>([]);
  const [workoutName, setWorkoutName] = useState("");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(true); // Модальное окно открыто по умолчанию

  useEffect(() => {
    if (token && id) {
      loadWorkoutData();
    }
  }, [token, id]);

  const loadWorkoutData = async () => {
    if (!token || !id) return;

    try {
      setLoading(true);
      const workout = await workoutsService.getWorkoutById(id, token);
      setWorkoutName(workout.name);
      setExercises(workout.exercises);
    } catch (err) {
      setError(
        err instanceof Error ? err.message : "Ошибка загрузки тренировки",
      );
    } finally {
      setLoading(false);
    }
  };

  const handleProfileClick = () => {
    navigate("/profile");
  };

  const handleAddCourse = () => {
    navigate("/courses");
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    navigate(`/training/${id}`);
  };

  const handleOverlayClick = (e: React.MouseEvent) => {
    if (e.target === e.currentTarget) {
      handleCloseModal();
    }
  };

  const handleSaveProgress = async (progressData: number[]) => {
    if (!token || !id) return;

    try {
      // TODO: Нужно передавать courseId
      // await workoutsService.saveWorkoutProgress(courseId, id, progressData, token);
      console.log("Progress saved:", progressData);
      navigate(`/training/${id}/success`);
    } catch (err) {
      console.error("Error saving progress:", err);
      throw err;
    }
  };

  const calculateProgress = (exercise: Exercise, value: number) => {
    return exercise.quantity > 0
      ? Math.round((value / exercise.quantity) * 100)
      : 0;
  };

  if (loading) return <div className={styles.loading}>Загрузка...</div>;
  if (error) return <div className={styles.error}>{error}</div>;

  return (
    <div className={styles.page}>
      <div className={styles.pageOverlay} onClick={handleOverlayClick} />

      <img
        src={`${process.env.PUBLIC_URL}/images/logo.svg`}
        alt="SkyFitnessPro"
        className={styles.logo}
      />

      <div className={styles.userProfileWrapper}>
        <UserProfile
          userName={userName}
          userEmail={userEmail}
          token={token}
          onProfileClick={handleProfileClick}
          onLogout={onLogout}
          onAddCourse={handleAddCourse}
        />
      </div>

      <div className={styles.contentBlock}>
        <h1 className={styles.title}>{workoutName || "Тренировка"}</h1>

        <div className={styles.videoContainer}>
          <img
            src={`${process.env.PUBLIC_URL}/images/vid1.svg`}
            alt="Video"
            className={styles.videoImage}
          />
        </div>

        <div className={styles.exercisesBlock}>
          <div className={styles.exercisesContent}>
            <h2 className={styles.exercisesTitle}>Упражнения тренировки</h2>

            <div className={styles.exercisesGrid}>
              {[0, 1, 2].map((colIndex) => (
                <div key={colIndex} className={styles.exerciseColumn}>
                  {exercises
                    .slice(colIndex * 3, colIndex * 3 + 3)
                    .map((exercise) => (
                      <div key={exercise._id} className={styles.exerciseItem}>
                        <p className={styles.exerciseText}>
                          {exercise.name} 0%
                        </p>
                        <div className={styles.progressBarBg}>
                          <div
                            className={styles.progressBarFill}
                            style={{ width: "0%" }}
                          />
                        </div>
                      </div>
                    ))}
                </div>
              ))}
            </div>

            <button className={styles.progressButton} onClick={() => {}}>
              Заполнить свой прогресс
            </button>
          </div>
        </div>
      </div>

      <ProgressModal
        isOpen={isModalOpen}
        onClose={handleCloseModal}
        workoutId={id || ""}
        courseId="" // TODO: Нужно передавать courseId
        exercises={exercises}
        onSave={handleSaveProgress}
      />
    </div>
  );
};

export default TrainingPageWithModal;
